import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from '@/components/jetbrains-ui/tooltip';
import { Button } from '@/components/jetbrains-ui/button';

interface TooltipDemoProps {
  side: 'top' | 'right' | 'bottom' | 'left';
}

export default function TooltipDemo({ side }: TooltipDemoProps) {
  return (
    <TooltipProvider>
      <Tooltip>
        <TooltipTrigger asChild>
          <Button variant="secondary">Hover Me</Button>
        </TooltipTrigger>
        <TooltipContent side={side}>Tooltip content</TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}
